import queue

# 输入获取
taskNum = int(input())
ranges = [list(map(int, input().split())) for i in range(taskNum)]


# 算法入口
def getResult(ranges):
    ranges.sort(key=lambda x: x[0])
    end = queue.PriorityQueue()
    maxV = 0
    sum = 0

    for ran in ranges:
        s, e, p = ran

        while end.qsize() > 0:
            top = end.queue[0]

            if top[0] <= s:
                poll = end.get()
                sum -= poll[1]
            else:
                break

        end.put((e, p))
        sum += p

        if sum > maxV:
            maxV = sum

    return maxV


# 算法调用
print(getResult(ranges))
